SELECT DEPT_HEAD_EMP_NO
FROM DEPT
WHERE DEPT_CD = #{deptCd}

SELECT COUNT(1)
FROM APRV_DOC d
WHERE 1=1


      AND d.EMP_NO = #{empNo}


      AND EXISTS (
        SELECT 1
        FROM APRV_LINE l
        WHERE l.APRV_NO = d.APRV_NO
          AND l.EMP_NO = #{empNo}
          AND l.STAT_CD = 'WAIT'
      )


      AND EXISTS (
        SELECT 1
        FROM APRV_LINE l
        WHERE l.APRV_NO = d.APRV_NO
          AND l.EMP_NO = #{empNo}
          AND l.STAT_CD IN ('APPROVED','REJECTED')
      )


      AND EXISTS (
        SELECT 1
        FROM APRV_REF r
        WHERE r.APRV_NO = d.APRV_NO
          AND r.EMP_NO = #{empNo}
      )


      AND d.EMP_NO = #{empNo}





    AND TRUNC(NVL(d.SUBMIT_DTM, SYSDATE)) >= TO_DATE(#{cond.fromDt}, 'YYYY-MM-DD')


    AND TRUNC(NVL(d.SUBMIT_DTM, SYSDATE)) <= TO_DATE(#{cond.toDt}, 'YYYY-MM-DD')



    AND d.STAT_CD = #{cond.docStatCd}


    AND d.FORM_CD = #{cond.formCd}


    AND d.APRV_NO = #{cond.aprvNoNum}


    AND d.APRV_TTL LIKE #{cond.aprvTtlPrefix} || '%'

SELECT * FROM ( SELECT ROW_NUMBER() OVER (ORDER BY d.APRV_NO DESC) AS RN,
d.APRV_NO, ft.FORM_NM, d.APRV_TTL,
d.STAT_CD AS DOC_STAT_CD, sc.STAT_NM AS DOC_STAT_NM,
/* stepText: current/total (RETIRE 자동승인은 0/0 가능) */ (CASE WHEN NVL(ls.total_cnt, 0) = 0 THEN '0/0' WHEN d.STAT_CD = 'APPROVED' THEN TO_CHAR(ls.total_cnt) || '/' || TO_CHAR(ls.total_cnt) WHEN d.STAT_CD IN ('SUBMITTED','IN_PROGRESS') THEN TO_CHAR(LEAST(NVL(ls.approved_cnt,0) + 1, ls.total_cnt)) || '/' || TO_CHAR(ls.total_cnt) WHEN d.STAT_CD IN ('REJECTED') THEN TO_CHAR(LEAST(NVL(ls.approved_cnt,0) + 1, ls.total_cnt)) || '/' || TO_CHAR(ls.total_cnt) ELSE '0/' || TO_CHAR(ls.total_cnt) END) AS STEP_TEXT,
/* 작성일: SUBMIT_DTM 없으면 '-' */ (CASE WHEN d.SUBMIT_DTM IS NOT NULL THEN TO_CHAR(d.SUBMIT_DTM, 'YYYY-MM-DD') ELSE '-' END) AS REG_DT,
/* 최종처리: FINAL_DTM > 마지막 라인처리일 > SUBMIT_DTM > '-' */ (CASE WHEN d.FINAL_DTM IS NOT NULL THEN TO_CHAR(d.FINAL_DTM, 'YYYY-MM-DD') WHEN ls.last_line_dtm IS NOT NULL THEN TO_CHAR(ls.last_line_dtm, 'YYYY-MM-DD') WHEN d.SUBMIT_DTM IS NOT NULL THEN TO_CHAR(d.SUBMIT_DTM, 'YYYY-MM-DD') ELSE '-' END) AS LAST_PROC_DT
FROM APRV_DOC d LEFT JOIN APRV_FORM_TYPE ft ON ft.FORM_CD = d.FORM_CD LEFT JOIN APRV_STAT_CD sc ON sc.STAT_DIV = 'DOC' AND sc.STAT_CD = d.STAT_CD
/* 라인 집계 */ LEFT JOIN ( SELECT l.APRV_NO, COUNT(*) AS total_cnt, SUM(CASE WHEN l.STAT_CD = 'APPROVED' THEN 1 ELSE 0 END) AS approved_cnt, MAX(l.APRV_DTM) AS last_line_dtm FROM APRV_LINE l GROUP BY l.APRV_NO ) ls ON ls.APRV_NO = d.APRV_NO
WHERE 1=1
AND d.EMP_NO = #{empNo}
AND EXISTS ( SELECT 1 FROM APRV_LINE l WHERE l.APRV_NO = d.APRV_NO AND l.EMP_NO = #{empNo} AND l.STAT_CD = 'WAIT' )
AND EXISTS ( SELECT 1 FROM APRV_LINE l WHERE l.APRV_NO = d.APRV_NO AND l.EMP_NO = #{empNo} AND l.STAT_CD IN ('APPROVED','REJECTED') )
AND EXISTS ( SELECT 1 FROM APRV_REF r WHERE r.APRV_NO = d.APRV_NO AND r.EMP_NO = #{empNo} )
AND d.EMP_NO = #{empNo}
AND TRUNC(NVL(d.SUBMIT_DTM, SYSDATE)) >= TO_DATE(#{cond.fromDt}, 'YYYY-MM-DD')
AND TRUNC(NVL(d.SUBMIT_DTM, SYSDATE)) <= TO_DATE(#{cond.toDt}, 'YYYY-MM-DD')
AND d.STAT_CD = #{cond.docStatCd}
AND d.FORM_CD = #{cond.formCd}
AND d.APRV_NO = #{cond.aprvNoNum}
AND d.APRV_TTL LIKE #{cond.aprvTtlPrefix} || '%'
) WHERE RN BETWEEN #{startRow} AND #{endRow} ORDER BY RN

SELECT COUNT(1)
FROM APRV_DOC
WHERE APRV_NO = #{aprvNo}
  AND EMP_NO = #{empNo}

