UPDATE APRV_LINE
SET STAT_CD = 'APPROVED',
    APRV_DTM = SYSDATE
WHERE LINE_NO = #{lineNo}
  AND EMP_NO = #{empNo}
  AND STAT_CD = 'WAIT'

mapper.select:
SELECT CASE WHEN COUNT(1) > 0 THEN 1 ELSE 0 END AS OK
FROM (
  /* 1) 작성자 */
  SELECT 1
  FROM APRV_DOC d
  WHERE d.APRV_NO = #{aprvNo}
    AND d.EMP_NO = #{empNo}

  UNION ALL

  /* 2) 결재선 포함 */
  SELECT 1
  FROM APRV_LINE l
  WHERE l.APRV_NO = #{aprvNo}
    AND l.EMP_NO = #{empNo}

  UNION ALL

  /* 3) 참조/수신 포함 */
  SELECT 1
  FROM APRV_REF r
  WHERE r.APRV_NO = #{aprvNo}
    AND r.EMP_NO = #{empNo}
)

