  APRV_NO, TARGET_EMP_NO, BEF_DEPT_CD, AFT_DEPT_CD, APPT_TYPE_CD, EFFECTIVE_DT, BEF_POS_CD, AFT_POS_CD, REASON
) VALUES (
  #{aprvNo}, #{targetEmpNo}, #{befDeptCd}, #{aftDeptCd}, #{apptTypeCd}, #{effectiveDt,jdbcType=DATE}, #{befPosCd}, #{aftPosCd}, #{reason}
)

INSERT INTO APRV_RETIRE (
  RETR_NO, APRV_NO, EMP_NO, EXP_RETR_DT, RETR_RSN, PROC_STAT_CD, CONF_RETR_DTM, E_APPR_DOC_NO, REQ_DTM, PROC_END_DTM
) VALUES (
  #{retrNo}, #{aprvNo}, #{empNo}, #{expRetrDt,jdbcType=DATE}, #{retrRsn}, #{procStatCd},
  #{confRetrDtm,jdbcType=TIMESTAMP}, #{eApprDocNo}, #{reqDtm,jdbcType=TIMESTAMP}, #{procEndDtm,jdbcType=TIMESTAMP}
)

